sourcesContent:
export const dimensions = [
  /* ===================== EI ===================== */
  {
    key: "EI",
    title: "ენერგიის წყარო (E / I)",
    intro:
      "ზომავს, საიდან იღებთ ენერგიას: ადამიანებთან ურთიერთობიდან (E) თუ განმარტოებით, შინაგანად (I).",
    questions: [
      {
        text: "ხანგრძლივი სამუშაო დღის შემდეგ, თქვენთვის ენერგიის აღდგენისა და განტვირთვის საუკეთესო გზაა:",
        a: { text: "ადამიანებთან ურთიერთობა", value: "E" },
        b: { text: "განმარტოება, ფიქრი", value: "I" }
      },
      {
        text: "მნიშვნელოვანი აზრის ჩამოყალიბებისას, სათქმელს:",
        a: { text: "საუბრის პარალელურად ალაგებთ", value: "E" },
        b: { text: "ფიქრის შემდეგ ახმოვანებთ", value: "I" }
      },
      {
        text: "ხანგრძლივი სოციალური აქტივობა თქვენთვის:",
        a: { text: "სტიმულისა და მოტივაციის მომცემია", value: "E" },
        b: { text: "დამღლელია", value: "I" }
      },
      {
        text: "ახალი ჯგუფის გაცნობისას, საუბარში:",
        a: { text: "ადვილად , მალევე ერთვებით ", value: "E" },
        b: { text: "აკვირდები სიტუაციას და  ნელ-ნელა ერთვები ", value: "I" }
      },
      {
        text: "ემოციური სტრესის დროს:",
        a: { text: "სხვებთან საუბარი გეხმარებათ სიტუაციის გაანალიზებაში", value: "E" },
        b: { text: "პირველ რიგში მარტო ყოფნა და ფიქრი გჭირდებათ", value: "I" }
      },
      {
        text: "პრობლემის გადაჭრისას ხშირად:",
        a: { text: "პასუხებს დიალოგსა და სხვებთან აზრების გაცვლაში პოულობთ ", value: "E" },
        b: { text: "დამოუკიდებლად  აანალიზებთ სიტუაციას და ისე მიდიხართ დასკვნამდე  ", value: "I" }
      },
      {
        text: "თქვენთვის „კარგი დღე“, ძირითადად,ნიშნავს:",
        a: { text: "აქტიურ კომუნიკაციას, დადებითი ემოციებით დატვირთულ დღეს", value: "E" },
        b: { text: "მშვიდ და პირად დროს", value: "I" }
      },
      {
        text: "დაუგეგმავ სოციალურ ღონისძიებაზე მიწვევისას თქვენი პირველი რეაქციაა:",
        a: { text: "ინტერესი და დასწრების სურვილი ", value: "E" },
        b: { text: "სიფრთხილე, დაფიქრდებით, გსურთ თუ არა დასწრება ", value: "I" }
      },
      {
        text: "თვისუფალ დროს:",
        a: { text: "ცდილობთ სხვებთან კონტაქტს", value: "E" },
        b: { text: "იყენებთ პირადი ინტერესებისთვის ან მარტო ყოფნისთვის ", value: "I" }
      },
      {
        text: "ხანგრძლივი მარტოობა:",
        a: { text: "გღლით", value: "E" },
        b: { text: "გაძლიერებთ", value: "I" }
      },
      {
        text: "მეგობრებთან:",
        a: { text: "გაქვთ ხშირი კონტაქტი", value: "E" },
        b: { text: "გაქვთ იშვიათი, მაგრამ ღრმა ურთიერთობები", value: "I" }
      },
      {
        text: "დადებითი ენერგიის წყარო ძირითადად არის:",
        a: { text: "გარემო და ადამიანები", value: "E" },
        b: { text: "შინაგანი სამყარო, ფიქრი", value: "I" }
      },
      {
        text: "მეგობრულ ურთიერთობებში თქვენთვის უფრო ბუნებრივია",
        a: { text: "ფართო წრის ყოლა და ხშირი კომუნიკაცია ", value: "E" },
        b: { text: "მცირე, შერჩეული წრის შენარჩუნება", value: "I" }
      }
    ],
    descriptions: {
      E: "E — ენერგიას იღებთ ადამიანებთან აქტიური ურთიერთობით.",
      I: "I — ენერგიას იღებთ განმარტოებით და შინაგანი კონცენტრაციით."
    }
  },

  /* ===================== SN ===================== */
  {
    key: "SN",
    title: "ინფორმაციის აღქმა (S / N)",
    intro:
      "ზომავს, როგორ აღიქვამთ და ამუშავებთ ინფორმაციას: არსებული ფაქტებით (S) თუ იდეებით (N).",
    questions: [
      {
        text: "ახალი ინფორმაციის გაცნობისას, ხშირად გამახსოვრდებათ:",
        a: { text: "კონკრეტულ ფაქტები და დეტალები", value: "S" },
        b: { text: "საერთო აზრი, კონცეფცია", value: "N" }
      },
      {
        text: "ყოველდღიურად, თქვენი ყურადღება მიმართულია:",
        a: { text: "არსებულ რეალობაზე, აქ და ახლა", value: "S" },
        b: { text: "შესაძლო შედეგებსა და მომავალ პერსპექტივებზე", value: "N" }
      },
      {
        text: "ინფორმაციის შეფასებისას თქვენთვის მნიშვნელოვანია:",
        a: { text: "მისი პრაქტიკული გამოყენება რეალურ გარემოში", value: "S" },
        b: { text: "მისი განვითარებისა და გამოყენების პოტენციალი", value: "N" }
      },
      {
        text: "როცა თქვენს პროფესიაში უკვე დიდ გამოცდილებას ფლობთ და საქმეს კარგად აკეთებთ, თქვენ ხშირად გიჩნდებათ სურვილი:",
        a: { text: "დარჩეთ ნაცნობი მიმართულების ფარგლებში, რაც რეალურ შედეგს გაძლევთ და თქვენს სფეროში განამტკიცოთ შესაძლებლობები ", value: "S" },
        b: { text: "მუდმივად შეისწავლოთ ახალი საკითხები,იდეები, მიუხედავად იმისა, ეხება თუ არა ეს თქვენს კონკრეტულ პროფესიას, რადგან ხედავთ ამ ცოდნის გამოყენების პოტენციალს ", value: "N" }
      },
      {
        text: "ახალი იდეის შეფასებისას თქვენთვის მნიშვნელოვანია:",
        a: { text: "რა შედეგს მოიტანს პრაქტიკაში ", value: "S" },
        b: { text: "რამდენად ინოვაციურია ", value: "N" }
      },
      {
        text: "საუბრის დროს, ძირითადად, ამჩნევთ:",
        a: { text: "დეტალებს, ფაქტობრივ უზუსტობებს და კონკრეტულ მაგალითებს", value: "S" },
        b: { text: "ქვეტექსტს, მინიშნებებსა და უთქმელ აზრებს", value: "N" }
      },
      {
        text: "ინსტრუქციის შესრულებისას:",
        a: { text: "ნაბიჯ-ნაბიჯ მიჰყვებით მითითებებს", value: "S" },
        b: { text: "ინარჩუნებთ ზოგად ჩარჩოს", value: "N" }
      },
      {
        text: "რაიმეს აღწერისას თქვენ:",
        a: { text: "ქმნით რეალისტურ სურათს დეტალებითა და მაგალითებით ", value: "S" },
        b: { text: "გადმოსცემთ ზოგად აზრსა და მნიშვნელობას", value: "N" }
      },
      {
        text: "ადამიანის გაცნობისას თქვენ ძირითადად გამახსოვრდებათ:",
        a: { text: "სახელი, ჩაცმულობა, კონკრეტულიქცევა", value: "S" },
        b: { text: "პიროვნების ზოგად შთაბეჭდილება და ენერგია", value: "N" }
      },
      {
        text: "რაიმე ამბის მოსმენისას დეტალების სიჭარბე თქვენთვის:",
        a: { text: "სიტუაციის აღქმას გიმარტივებთ", value: "S" },
        b: { text: "გაბნევთ", value: "N" }
      },
      {
        text: "მომავალზე ფიქრისას თქვენ:",
        a: { text: "ხედავთ რეალისტურ სავარაუდო სცენარს", value: "S" },
        b: { text: "ერთდროულად განიხილავთ მრავალ შესაძლო ვარიანტს", value: "N" }
      },
      {
        text: "წაკითხული წიგნებიდან თუ ნანახი ფილმებიდან უფრო მეტად გამახსოვრდებათ:",
        a: { text: "კონკრეტული სახელები, ფაქტები და ავტორები", value: "S" },
        b: { text: "იდეები, თემები და როგორ უკავშირდება ისინი სხვა წაკითხულ ან გაგონილ კონცეფციებს", value: "N" }
      },
      {
        text: "როცა რამე არ ემთხვევა გამოცდილ რეალობას, თქვენ:",
        a: { text: "სკეპტიკურად აფასებთ და ამოწმებთ ფაქტებს", value: "S" },
        b: { text: "ინტერესით იკვლევთ, რა ახალი შესაძლებლობა შეიძლება იმალებოდეს", value: "N" }
      }
    ],
    descriptions: {
      S: "S — ფაქტებსა და რეალობაზე ორიენტირებული.",
      N: "N — იდეებსა და შესაძლებლობებზე ორიენტირებული."
    }
  },

  /* ===================== TF ===================== */
  {
    key: "TF",
    title: "გადაწყვეტილების მიღება (T / F)",
    intro:
      "ზომავს, როგორ იღებთ გადაწყვეტილებებს — ლოგიკურ ანალიზზე (T) თუ ემოციურ შეფასებაზე (F) დაყრდნობით.",
    questions: [
      {
        text: "მეგობრის პრობლემის მოსმენისას, პირველ რიგში:",
        a: { text: "ლოგიკურ გამოსავალს სთავაზობთ", value: "T" },
        b: { text: "ემოციურად უჭერთ მხარს", value: "F" }
      },
      {
        text: "რთულ პროექტზე ჯგუფური მუშაობისას, პირველად თქვენი  ყურადღება  მახვილდება:",
        a: { text: "შედეგის ეფექტურობასა და შესაძლო შეცდომების ანალიზზე", value: "T" },
        b: { text: "გუნდში მყოფ ადამიანებზე,  ურთიერთობების ჰარმონიასა თუ დაძაბულ სიტუაციებზე", value: "F" }
      },
      {
        text: "კრიტიკის მიღებისას, პირველ რიგში კონცენტრირდებით: ",
        a: { text: "ნათქვამის შეინაარსზე", value: "T" },
        b: { text: "ნათქვამის ტონზე ", value: "F" }
      },
      {
        text: "რა უფრო მიუღებელია თვენთვის:",
        a: { text: "არაგონივრული გადაწყვეტილების მიღება", value: "T" },
        b: { text: "ადამიანისთვის ემოციური ზიანის მიყება", value: "F" }
      },
      {
        text: "კონფლიქტურ სიტუაციას აგვარებთ:",
        a: { text: "ლოგიკური ფაქტებით, ობიექტურად", value: "T" },
        b: { text: "მხარეთა განცდების გათვალისწინებით", value: "F" }
      },
      {
        text: "კონკრეტულ შესრულებულ სამუშაოს აფასებთ:",
        a: { text: "შედეგებიდან გამომდინარე", value: "T" },
        b: { text: "ჯგუფისა და პროცესის მდგომარეობის გათვალისწინებით", value: "F" }
      },
      {
        text: "თვენთვის რთულ სიტუაციაში მნიშვნელოვანია:",
        a: { text: "სიმართლე", value: "T" },
        b: { text: "ემოციური მხარდაჭერა", value: "F" }
      },
      {
        text: "გადაწყვეტილების მიღებისას ეყრდნობით:",
        a: { text: "ობიექტურობას, ფაქტებს", value: "T" },
        b: { text: "ღირებულებებს, პირად დამოკიდებულებებს", value: "F" }
      },
      {
        text: "ახალი თანამშრომლის შეფასებისას,  თქვენთვის ყველაზე მნიშვნელოვანია:",
        a: { text: "უნარები, შედეგები, საქმის შესრულების დონე", value: "T" },
        b: { text: "პიროვნული თვისებები", value: "F" }
      },
      {
        text: "თვენთვის მორალი ეფუძნება:",
        a: { text: "ობიექტურობას, პრინციპებს", value: "T" },
        b: { text: "ემპათიას", value: "F" }
      },
      {
        text: "როდესაც ფილმს უყურებთ და მთავარი გმირი რთულ არჩევანს აკეთებს, თქვენი ყურადღება მახვილდება:",
        a: { text: "გმირის გადაწყვეტილების ანალიზზე — ლოგიკური შეფასება", value: "T" },
        b: { text: "გმირის გრძნობებსა და მოტივებზე — ემოციური შეფსება", value: "F" }
      },
      {
        text: "კონფლიქტურ სიტუაციაში გირჩევნიათ:",
        a: { text: "თქვათ სიმართლე", value: "T" },
        b: { text: "შეინარჩუნოთ ჰარმონია", value: "F" }
